+    const [root, collection] = path.split(/\\.(map:|set:)/)
+    let value = logic.selector!(state)[root]
+    if (!collection) {
+      for (const part of path.split('.').slice(1)) value = value == null ? undefined : value[part]
+      return value
+    }
+    const suffix = path.slice(root.length + 1 + collection.length)
+    return collection === 'map:' ? value?.get(suffix) : value?.has(suffix)
+  }
+
+  function wrap(value: any, path: string, dependencies: Set<string>): any {
+    if (!isObject(value)) {
+      dependencies.add(path)
+      return value
+    }
+    if (value instanceof Map) {
+      return new Proxy(value, {
+        get(target, property) {
+          if (property === 'get') return (mapKey: any) => {
+            const dependency = `${path}.map:${key(mapKey)}`
+            dependencies.add(dependency)
+            return wrap(target.get(mapKey), dependency, dependencies)
+          }
+          if (property === 'has') return (mapKey: any) => {
+            dependencies.add(`${path}.map:${key(mapKey)}`)
+            return target.has(mapKey)
+          }
+          if (property === 'size') {
+            dependencies.add(`${path}.size`)
+            return target.size
+          }
+          const result = Reflect.get(target, property, target)
+          return typeof result === 'function' ? result.bind(target) : result
+        },
+      })
+    }
+    if (value instanceof Set) {
+      return new Proxy(value, {
+        get(target, property) {
+          if (property === 'has') return (setValue: any) => {
+            dependencies.add(`${path}.set:${key(setValue)}`)
+            return target.has(setValue)
+          }
+          if (property === 'size') {
+            dependencies.add(`${path}.size`)
+            return target.size
+          }
+          const result = Reflect.get(target, property, target)
